`, "",{"version":3,"sources":["webpack://./src/STH_ExportAll/界面.vue"],"names":[],"mappings":"AAySA,uCACE,YAAa,CACb,qBAAsB,CACtB,QAAS,CACT,cACF,CAEA,sCACE,YAAa,CACb,eACF,CAEA,wCACE,cAAe,CACf,YAAa,CACb,eAAgB,CAChB,oBACF","sourcesContent":["<template>\n  <div class=\"sth-export-all\">\n    <div class=\"inline-drawer\">\n      <div class=\"inline-drawer-toggle inline-drawer-header\">\n        <b style=\"writing-mode: horizontal-tb\">一键导出</b>\n        <div class=\"inline-drawer-icon fa-solid fa-circle-chevron-down down\"></div>\n      </div>\n      <div class=\"inline-drawer-content\">\n        <div class=\"sth-export-all-block\">\n          <div class=\"sth-export-all-desc\">导出所有聊天文件</div>\n          <button id=\"sth_export_btn\" class=\"menu_button\" :disabled=\"isExporting\" style=\"writing-mode: horizontal-tb\" @click=\"handleExport\">\n            {{ isExporting ? '导出中...' : '一键导出' }}\n          </button>\n          <div v-if=\"exportStatus\" id=\"sth_export_status\" class=\"sth-export-all-status\">\n            {{ exportStatus }}\n          </div>\n        </div>\n        <hr class=\"sysHR\" />\n      </div>\n    </div>\n  </div>\n</template>\n\n<script setup lang=\"ts\">\nconst isExporting = ref(false);\nconst exportStatus = ref('');\n\nconst handleExport = async () => {\n  if (isExporting.value) return;\n\n  isExporting.value = true;\n  exportStatus.value = '正在加载压缩库...';\n\n  try {\n    const JSZip = await ensureJSZip();\n\n    exportStatus.value = '正在读取角色列表...';\n\n    const characters = await fetchAllCharacters();\n\n    if (!characters.length) {\n      throw new Error('未找到角色');\n    }\n\n    const zip = new JSZip();\n\n    let totalChats = 0;\n    let exportedChats = 0;\n\n    const allChatMap: { character: any; chat: any }[] = [];\n\n    for (const character of characters) {\n      const chats = await fetchChatsFor(character.avatar);\n\n      for (const chat of chats) {\n        allChatMap.push({ character, chat });\n      }\n    }\n\n    totalChats = allChatMap.length;\n\n    if (totalChats === 0) {\n      throw new Error('没有聊天记录');\n    }\n\n    for (const item of allChatMap) {\n      const { character, chat } = item;\n\n      exportedChats++;\n\n      const characterName = safeFileName(character.name || 'UnknownCharacter');\n      const fileName = safeFileName(stripExt(chat.file_name || 'chat'));\n\n      exportStatus.value = `正在导出 ${exportedChats}/${totalChats} : ${characterName} / ${fileName}`;\n\n      try {\n        const arr = await fetchFullChat(character, fileName);\n\n        const jsonl = arr.map(v => JSON.stringify(v)).join('\\n');\n\n        zip.file(`${characterName}/${fileName}.jsonl`, jsonl);\n      } catch (err) {\n        console.warn('[STH_ExportAll] export failed:', characterName, fileName, err);\n      }\n    }\n\n    exportStatus.value = '正在生成 ZIP...';\n\n    const blob = await zip.generateAsync({\n      type: 'blob',\n      compression: 'DEFLATE',\n      compressionOptions: { level: 6 },\n    });\n\n    const time = new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19);\n\n    downloadBlob(blob, `SillyTavern_All_Chats_${time}.zip`);\n\n    exportStatus.value = `导出完成，共 ${exportedChats} 个聊天文件`;\n    toastr.success(`导出完成，共 ${exportedChats} 个聊天文件`);\n\n    _.delay(() => {\n      exportStatus.value = '';\n    }, 3000);\n  } catch (err) {\n    console.error('[STH_ExportAll] failed:', err);\n    exportStatus.value = `导出失败: ${(err as Error).message}`;\n    toastr.error(`导出失败: ${(err as Error).message}`);\n  } finally {\n    isExporting.value = false;\n  }\n};\n\n// Exact copy from 一键导出.js\nfunction headers() {\n  if (typeof (window as any).getRequestHeaders === 'function') {\n    return (window as any).getRequestHeaders();\n  }\n\n  if ((window as any).SillyTavern?.getContext) {\n    try {\n      const ctx = (window as any).SillyTavern.getContext();\n\n      if (typeof (ctx as any).getRequestHeaders === 'function') {\n        return (ctx as any).getRequestHeaders();\n      }\n    } catch {\n      // SillyTavern.getContext not available\n    }\n  }\n\n  return {\n    'Content-Type': 'application/json',\n  };\n}\n\nfunction stripExt(name: string): string {\n  return String(name || '').replace(/\\.jsonl$/i, '');\n}\n\nfunction withExt(name: string): string {\n  return stripExt(name) + '.jsonl';\n}\n\nfunction safeFileName(name: string): string {\n  return String(name || 'unknown')\n    .replace(/[\\\\/:*?\"<>|]/g, '_')\n    .replace(/\\s+/g, ' ')\n    .trim();\n}\n\nasync function fetchAllCharacters(): Promise<any[]> {\n  let raw: any[] | null = null;\n\n  try {\n    const ctx = (SillyTavern as any).getContext?.();\n\n    if (ctx?.characters?.length) {\n      raw = ctx.characters;\n    }\n  } catch {\n    // SillyTavern not available\n  }\n\n  if (!raw) {\n    const res = await fetch('/api/characters/all', {\n      method: 'POST',\n      headers: headers(),\n      body: JSON.stringify({}),\n    });\n\n    if (!res.ok) {\n      throw new Error(`角色列表读取失败: ${res.status}`);\n    }\n\n    raw = await res.json();\n  }\n\n  const seen = new Set<string>();\n\n  return (Array.isArray(raw) ? raw : []).filter(c => {\n    if (!c || !c.avatar) return false;\n\n    if (seen.has(c.avatar)) {\n      return false;\n    }\n\n    seen.add(c.avatar);\n\n    return true;\n  });\n}\n\nasync function fetchChatsFor(avatar: string): Promise<any[]> {\n  const res = await fetch('/api/characters/chats', {\n    method: 'POST',\n    headers: headers(),\n    body: JSON.stringify({\n      avatar_url: avatar,\n    }),\n  });\n\n  if (!res.ok) {\n    throw new Error(`聊天列表读取失败: ${res.status}`);\n  }\n\n  const data = await res.json();\n\n  if (data && typeof data === 'object' && data.error === true) {\n    return [];\n  }\n\n  return Array.isArray(data) ? data : Object.values(data || {});\n}\n\nasync function fetchFullChat(character: any, fileName: string): Promise<any[]> {\n  const bodies = [\n    {\n      ch_name: character.name,\n      file_name: stripExt(fileName),\n      avatar_url: character.avatar,\n      force: true,\n    },\n    {\n      avatar_url: character.avatar,\n      file_name: withExt(fileName),\n      force: true,\n    },\n    {\n      ch_name: character.name,\n      file_name: stripExt(fileName),\n      avatar_url: character.avatar,\n    },\n  ];\n\n  for (const body of bodies) {\n    try {\n      const res = await fetch('/api/chats/get', {\n        method: 'POST',\n        headers: headers(),\n        body: JSON.stringify(body),\n      });\n\n      if (!res.ok) {\n        continue;\n      }\n\n      const data = await res.json();\n\n      const arr = Array.isArray(data) ? data : data?.chat || [];\n\n      if (arr.length) {\n        return arr;\n      }\n    } catch (err) {\n      console.warn('[STH_ExportAll] fetch chat failed:', err);\n    }\n  }\n\n  throw new Error(`无法读取聊天: ${fileName}`);\n}\n\nasync function ensureJSZip(): Promise<any> {\n  if ((window as any).JSZip) {\n    return (window as any).JSZip;\n  }\n\n  console.log('[STH_ExportAll] loading JSZip...');\n\n  await new Promise((resolve, reject) => {\n    const s = document.createElement('script');\n    s.src = 'https://cdnjs.cloudflare.com/ajax/libs/jszip/3.10.1/jszip.min.js';\n    s.onload = () => resolve((window as any).JSZip);\n    s.onerror = () => reject(new Error('JSZip 加载失败'));\n    document.head.appendChild(s);\n  });\n\n  if (!(window as any).JSZip) {\n    throw new Error('JSZip 加载失败');\n  }\n\n  return (window as any).JSZip;\n}\n\nfunction downloadBlob(blob: Blob, filename: string): void {\n  const url = URL.createObjectURL(blob);\n  const a = document.createElement('a');\n  a.href = url;\n  a.download = filename;\n  document.body.appendChild(a);\n  a.click();\n  a.remove();\n  URL.revokeObjectURL(url);\n}\n</script>\n\n<style scoped>\n.sth-export-all-block {\n  display: flex;\n  flex-direction: column;\n  gap: 10px;\n  padding: 10px 0;\n}\n\n.sth-export-all-desc {\n  opacity: 0.85;\n  line-height: 1.5;\n}\n\n.sth-export-all-status {\n  font-size: 12px;\n  opacity: 0.75;\n  line-height: 1.5;\n  word-break: break-all;\n}\n</style>\n"],"sourceRoot":""}]);
